from agno import Agent
from pydantic import BaseModel, Field
from typing import List

class FactExtraction(BaseModel):
    facts: List[str]
    source: str = 'agent'

class ConsistentAgent(Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.response_model = FactExtraction

    def run_structured(self, query: str):
        try:
            result = self.run(query, response_model=self.response_model)
            return FactExtraction.model_validate(result)
        except Exception:
            # Fallback parsing
            raw = self.run(query)
            return FactExtraction.model_validate({'facts': [str(raw)], 'source': 'fallback'})

agent = ConsistentAgent(name='structured-agent')
facts = agent.run_structured('List 3 capitals in Europe')

from agno import Agent, Team
from collections import Counter

class ConsensusTeam(Team):
    def coordinate(self, query: str):
        responses = []
        for agent in self.agents:
            responses.append(agent.run(query))

        # Extract key facts and find consensus
        facts = []
        for resp in responses:
            facts.extend(str(resp).lower().split('.'))

        fact_counts = Counter(facts)
        consensus_facts = [fact for fact, count in fact_counts.items() if count > len(self.agents)/2]

        return {'consensus_facts': consensus_facts, 'agreement_rate': len(consensus_facts)/len(facts)}

team = ConsensusTeam(agents=[Agent('researcher'), Agent('validator')])
result = team.coordinate('What are the main causes of climate change?')
